package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsCommentingEnabledWhenCommentStartIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set commentStart to null
        Field commentStartField = CSVFormat.class.getDeclaredField("commentStart");
        commentStartField.setAccessible(true);
        // CSVFormat fields are final, so remove final modifier via reflection
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(commentStartField, commentStartField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);
        commentStartField.set(format, null);

        assertFalse(format.isCommentingEnabled());
    }

    @Test
    void testIsCommentingEnabledWhenCommentStartIsChar() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withCommentStart('#');
        assertTrue(format.isCommentingEnabled());
    }

    @Test
    void testIsCommentingEnabledWhenCommentStartIsCharacterObject() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withCommentStart(Character.valueOf(';'));
        assertTrue(format.isCommentingEnabled());
    }
}
